SQLLite.SQL:
				
			   	SELECT SD.ITEM                AS "item"
        	   	,      TRUNC(SD.ITEM_VALUE,0) AS "itemValue"
        		,      SD.ADMIN_COURT_CODE    AS "adminCourtCode"   
  				FROM SYSTEM_DATA SD
  				WHERE SD.ITEM 			= ${param.runDate}
				AND SD.ITEM_VALUE 		= ${param.systemDate}
				AND SD.ADMIN_COURT_CODE = ${param.adminCourtCode}
